import{_ as e,o as d,c as l,ae as o}from"./chunks/framework.BzQXgbNp.js";const x=JSON.parse('{"title":"🛠️ 管理員指令與管理主控台指南","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Admin-Management.md","filePath":"Mc-Admin-Management.md"}'),a={name:"Mc-Admin-Management.md"};function n(s,t,r,i,c,g){return d(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="🛠️-管理員指令與管理主控台指南" tabindex="-1">🛠️ 管理員指令與管理主控台指南 <a class="header-anchor" href="#🛠️-管理員指令與管理主控台指南" aria-label="Permalink to &quot;🛠️ 管理員指令與管理主控台指南&quot;">​</a></h1><p>本章節完整列出 Craft-Core 伺服器管理員（OP）專用的遊戲內指令、Discord 管理員控制面板，以及 Web Dashboard 管理主控台的相關操作說明。</p><hr><h2 id="⚙️-1-遊戲內管理員-op-專用指令清單" tabindex="-1">⚙️ 1. 遊戲內管理員（OP）專用指令清單 <a class="header-anchor" href="#⚙️-1-遊戲內管理員-op-專用指令清單" aria-label="Permalink to &quot;⚙️ 1. 遊戲內管理員（OP）專用指令清單&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">說明</th><th style="text-align:left;">參數範例</th><th style="text-align:left;">備註</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>/addmoney &lt;玩家&gt; &lt;金額&gt;</code></strong></td><td style="text-align:left;">增加指定玩家的遊戲金幣餘額</td><td style="text-align:left;"><code>/addmoney Alex 5000</code></td><td style="text-align:left;">無需目標在線，金幣即時到帳</td></tr><tr><td style="text-align:left;"><strong><code>/removemoney &lt;玩家&gt; &lt;金額&gt;</code></strong></td><td style="text-align:left;">扣除指定玩家的遊戲金幣餘額</td><td style="text-align:left;"><code>/removemoney Alex 1000</code></td><td style="text-align:left;">最多扣至 $0，不會為負數</td></tr><tr><td style="text-align:left;"><strong><code>/setwarp &lt;地標名稱&gt;</code></strong></td><td style="text-align:left;">在管理員當前位置建立公共地標</td><td style="text-align:left;"><code>/setwarp spawn</code></td><td style="text-align:left;">全服玩家皆可透過 <code>/warp &lt;名稱&gt;</code> 傳送</td></tr><tr><td style="text-align:left;"><strong><code>/delwarp &lt;地標名稱&gt;</code></strong></td><td style="text-align:left;">刪除指定的公共地標</td><td style="text-align:left;"><code>/delwarp spawn</code></td><td style="text-align:left;">刪除後自動同步網頁與 Discord 列表</td></tr><tr><td style="text-align:left;"><strong><code>/invsee &lt;玩家&gt;</code></strong></td><td style="text-align:left;">遠端開啟並即時查看/編輯指定線上玩家的背包與裝備箱</td><td style="text-align:left;"><code>/invsee Alex</code></td><td style="text-align:left;">由伺服器整合包獨立背包模組提供</td></tr><tr><td style="text-align:left;"><strong><code>/ban &lt;玩家&gt; [原因]</code></strong></td><td style="text-align:left;">封鎖指定玩家並禁止登入</td><td style="text-align:left;"><code>/ban BadUser 破壞地形</code></td><td style="text-align:left;">自動發送廣播與紀錄</td></tr><tr><td style="text-align:left;"><strong><code>/kick &lt;玩家&gt; [原因]</code></strong></td><td style="text-align:left;">強制踢出指定線上玩家</td><td style="text-align:left;"><code>/kick AFKUser 佔用伺服器</code></td><td style="text-align:left;">踢出後可重新連線</td></tr><tr><td style="text-align:left;"><strong><code>/fp &lt;名稱&gt; &lt;動作&gt;</code></strong></td><td style="text-align:left;">管理員控制與清理假人</td><td style="text-align:left;"><code>/fp fp_alex kill</code></td><td style="text-align:left;">管理員擁有最高權限可強制下線任何假人</td></tr><tr><td style="text-align:left;"><strong><code>/shop list</code></strong></td><td style="text-align:left;">列出全服所有註冊商店</td><td style="text-align:left;"><code>/shop list</code></td><td style="text-align:left;">包含商店位置、擁有者與物品</td></tr><tr><td style="text-align:left;"><strong><code>/shop reload</code></strong></td><td style="text-align:left;">重新載入商店資料與設定檔</td><td style="text-align:left;"><code>/shop reload</code></td><td style="text-align:left;">當手動修改 JSON 設定檔時使用</td></tr></tbody></table><hr><h2 id="🏪-2-管理員無限商店-系統商店" tabindex="-1">🏪 2. 管理員無限商店（系統商店） <a class="header-anchor" href="#🏪-2-管理員無限商店-系統商店" aria-label="Permalink to &quot;🏪 2. 管理員無限商店（系統商店）&quot;">​</a></h2><p>管理員可建立免庫存、免資金的官方系統商店：</p><ol><li>按照常規方式放置箱子與告示牌建立商店，或對著現有商店告示牌點選 <strong>【右鍵】</strong> 開啟店主管理面板。</li><li>僅管理員（OP）能看見 <strong>「無限模式」</strong> 狀態，點選右側的 <strong><code>§d[切換無限]</code></strong> 按鈕進行切換。</li><li>啟用後，商店庫存會顯示為 <code>無限</code>，玩家可以無限制地進行買賣。</li><li><strong>遠端清空箱子</strong>：對著無限商店，點擊管理面板中的 <strong><code>[清空箱子]</code></strong> 按鈕，即可快速清空實體箱子中該商店類型的物品。</li></ol><hr><h2 id="🤖-3-discord-管理員控制面板-頻道-1524977578362933419" tabindex="-1">🤖 3. Discord 管理員控制面板 (頻道 <code>1524977578362933419</code>) <a class="header-anchor" href="#🤖-3-discord-管理員控制面板-頻道-1524977578362933419" aria-label="Permalink to &quot;🤖 3. Discord 管理員控制面板 (頻道 `1524977578362933419`)&quot;">​</a></h2><p>專為管理員設計的 Discord 遠端維護控制台，提供以下核心功能按鈕：</p><ul><li><strong>🚫 封鎖玩家 (admin_ban)</strong>：彈出 Modal 輸入玩家 ID 與理由，自動發送 <code>/ban</code> 命令。</li><li><strong>🥾 踢出玩家 (admin_kick)</strong>：彈出 Modal 輸入玩家 ID 與理由，自動發送 <code>/kick</code> 命令。</li><li><strong>🤝 聯名獎勵 (admin_co_brand)</strong>：輸入玩家名稱或 Discord ID，自動獎勵 <strong>$5,000 遊戲幣 + 6 把抽獎鑰匙</strong>！</li><li><strong>🔍 查詢玩家 (admin_search_player)</strong>：查詢指定玩家的餘額、線上/離線狀態、座標、TPS、簽到天數與背包物品。</li><li><strong>📢 發布全服公告 (admin_draft_announcement)</strong>：填寫公告主題與內文，進行預覽、發布或廢棄，發布時於遊戲內發送全服彩色廣播。</li><li><strong>📍 公共設施 Warp 審核審查</strong>：接收來自玩家提交的設施審核卡片，點擊 <code>✅ 同意通過並設立 Warp</code> 即可自動設立遊戲內地標並更新頻道 Embed！</li></ul><hr><h2 id="🖥️-4-web-dashboard-管理員主控台-admin" tabindex="-1">🖥️ 4. Web Dashboard 管理員主控台 (<code>/admin</code>) <a class="header-anchor" href="#🖥️-4-web-dashboard-管理員主控台-admin" aria-label="Permalink to &quot;🖥️ 4. Web Dashboard 管理員主控台 (`/admin`)&quot;">​</a></h2><p>網頁端儀表板為擁有管理員身分（<code>isAdmin</code>）的帳號提供專屬控制台：</p><ol><li><strong>玩家管理面板</strong>：可快速進行玩家 Ban/Kick 操作，並發送 $5,000 + 6 鑰匙聯名獎勵。</li><li><strong>玩家背包與個人資產檢視</strong>：輸入玩家名稱即可調閱其金幣餘額、座標、TPS、簽到數據與實體背包物品清單。</li><li><strong>🎪 伺服器活動發布與管理 (<code>/api/admin/events</code>)</strong>： <ul><li>建立全新的限時節慶、採礦雙倍、抽獎大賽活動。</li><li>設定活動標題、詳細說明、起訖時間、豐厚獎勵，並切換狀態 (<code>active</code> 🟢 / <code>paused</code> ⏸️ / <code>completed</code> ⚪)。</li></ul></li><li><strong>📍 公共設施 Warp 審核列表 (<code>/api/admin/warp-submissions</code>)</strong>： <ul><li>線上檢視所有玩家提交的公共設施（設施名稱、功能說明、座標、維度）。</li><li>提供一鍵 <code>✅ 同意通過</code>（自動建立 <code>/warp</code> 點）與 <code>❌ 駁回</code> 按鈕。</li></ul></li></ol>',17)])])}const h=e(a,[["render",n]]);export{x as __pageData,h as default};
